import { onLCP, onINP, onCLS, onTTFB } from 'web-vitals';

function sendToAnalytics(metric) {
  // metric = { name, value, rating, delta, id, navigationType }
  const body = JSON.stringify({
    name: metric.name,
    value: metric.value,
    rating: metric.rating,   // 'good' | 'needs-improvement' | 'poor'
    id: metric.id,
    path: location.pathname
  });
  // sendBeacon survives page unload; keeps the request off the critical path.
  (navigator.sendBeacon && navigator.sendBeacon('/rum', body)) ||
    fetch('/rum', { body, method: 'POST', keepalive: true });
}

onLCP(sendToAnalytics);
onINP(sendToAnalytics);
onCLS(sendToAnalytics);
onTTFB(sendToAnalytics);

// Raw LCP: the last entry before the user interacts is the real LCP.
new PerformanceObserver((list) => {
  const entries = list.getEntries();
  const last = entries[entries.length - 1];
  console.log('LCP', last.startTime, 'element:', last.element);
}).observe({ type: 'largest-contentful-paint', buffered: true });

// Raw CLS: sum shifts that were not caused by recent user input.
let cls = 0;
new PerformanceObserver((list) => {
  for (const entry of list.getEntries()) {
    if (!entry.hadRecentInput) {
      cls += entry.value;
      console.log('shift', entry.value, entry.sources?.map(s => s.node));
    }
  }
}).observe({ type: 'layout-shift', buffered: true });

// Long tasks (>50ms) are the raw material of poor INP.
new PerformanceObserver((list) => {
  for (const entry of list.getEntries()) {
    console.warn('long task', entry.duration, 'ms', entry.attribution);
  }
}).observe({ type: 'longtask', buffered: true });

// Route-level code-splitting: the chart bundle is only fetched when needed.
const routes = [
  {
    path: '/dashboard',
    // Dynamic import returns a promise; the bundler emits a separate chunk.
    component: () => import('./pages/Dashboard.js')
  }
];

// Interaction-level splitting: load the heavy editor only on demand.
button.addEventListener('click', async () => {
  const { openEditor } = await import('./editor.js'); // separate chunk
  openEditor();
}, { once: true });

// BAD: reads offsetWidth (forces layout) then writes, every iteration.
function resizeAll(boxes) {
  for (const box of boxes) {
    const w = box.offsetWidth;        // READ -> forces synchronous layout
    box.style.width = w * 1.5 + 'px'; // WRITE -> invalidates layout again
  }
}

// GOOD: batch all reads, then all writes. Layout is computed once.
function resizeAll(boxes) {
  const widths = boxes.map(box => box.offsetWidth); // all READS together
  boxes.forEach((box, i) => {                       // all WRITES together
    box.style.width = widths[i] * 1.5 + 'px';
  });
}

// Even better: schedule writes in requestAnimationFrame so they land
// just before the next paint, aligned with the browser's own cycle.
function animate(box, x) {
  requestAnimationFrame(() => {
    box.style.transform = `translateX(${x}px)`; // compositor-only, no layout
  });
}

async function processInChunks(items, handle) {
  const yieldToMain = () =>
    (window.scheduler?.yield?.() ?? new Promise(r => setTimeout(r, 0)));

  let start = performance.now();
  for (const item of items) {
    handle(item);
    // Yield if we have held the thread for ~50ms so input can be handled.
    if (performance.now() - start > 50) {
      await yieldToMain();
      start = performance.now();
    }
  }
}

@font-face {
  font-family: 'Inter';
  src: url('/fonts/inter.woff2') format('woff2');
  font-display: swap;              /* avoid invisible text */
  font-weight: 100 900;           /* variable font: one file, all weights */
}

/* Tune the fallback metrics so the swap does not shift layout (CLS). */
@font-face {
  font-family: 'Inter-fallback';
  src: local('Arial');
  size-adjust: 107%;
  ascent-override: 90%;
  descent-override: 22%;
}

// Debounce: run only after the burst of events stops (e.g. search input).
function debounce(fn, wait) {
  let t;
  return (...args) => {
    clearTimeout(t);
    t = setTimeout(() => fn(...args), wait);
  };
}

// Throttle: run at most once per interval (e.g. scroll position tracking).
function throttle(fn, interval) {
  let last = 0;
  return (...args) => {
    const now = performance.now();
    if (now - last >= interval) {
      last = now;
      fn(...args);
    }
  };
}

searchInput.addEventListener('input', debounce(runQuery, 300));
window.addEventListener('scroll', throttle(updateScrollSpy, 100), { passive: true });

// Node streaming SSR with React: flush the shell early, stream the rest.
import { renderToPipeableStream } from 'react-dom/server';

app.get('*', (req, res) => {
  const stream = renderToPipeableStream(<App url={req.url} />, {
    bootstrapScripts: ['/client.js'],
    onShellReady() {
      // TTFB win: send the shell before slow data resolves.
      res.setHeader('Content-Type', 'text/html');
      stream.pipe(res);
    },
    onError(err) { console.error(err); res.statusCode = 500; }
  });
});

