// vitals-rum.js - dependency-free Core Web Vitals reporting.
(function reportVitals() {
  const metrics = { LCP: 0, CLS: 0, INP: 0 };
  let reported = false;

  // ---- LCP: last candidate before first interaction ----
  let lcpDone = false;
  const lcpObserver = new PerformanceObserver((list) => {
    if (lcpDone) return;
    const entries = list.getEntries();
    const last = entries[entries.length - 1];
    if (last) metrics.LCP = Math.round(last.startTime);
  });
  lcpObserver.observe({ type: 'largest-contentful-paint', buffered: true });
  const stopLCP = () => { lcpDone = true; lcpObserver.disconnect(); };
  addEventListener('pointerdown', stopLCP, { once: true, capture: true });
  addEventListener('keydown', stopLCP, { once: true, capture: true });

  // ---- CLS: sum shifts without recent input ----
  new PerformanceObserver((list) => {
    for (const entry of list.getEntries()) {
      if (!entry.hadRecentInput) metrics.CLS += entry.value;
    }
  }).observe({ type: 'layout-shift', buffered: true });

  // ---- INP: worst interaction latency ----
  new PerformanceObserver((list) => {
    for (const entry of list.getEntries()) {
      if (entry.interactionId) {
        metrics.INP = Math.max(metrics.INP, Math.round(entry.duration));
      }
    }
  }).observe({ type: 'event', buffered: true, durationThreshold: 40 });

  // ---- Report once when the page is hidden ----
  function flush() {
    if (reported) return;
    reported = true;
    const body = JSON.stringify({
      lcp: metrics.LCP,
      cls: Math.round(metrics.CLS * 1000) / 1000,
      inp: metrics.INP,
      path: location.pathname
    });
    if (navigator.sendBeacon) navigator.sendBeacon('/rum', body);
    else fetch('/rum', { method: 'POST', body, keepalive: true });
  }
  addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'hidden') flush();
  });
  addEventListener('pagehide', flush);
})();
